  // Sort the valid coupons
  validCoupons.sort((a, b) => {
    const order = ["electronics", "grocery", "pharmacy", "restaurant"];
    const aOrder = order.indexOf(a.businessLine);
    const bOrder = order.indexOf(b.businessLine);
    if (aOrder !== bOrder) return aOrder - bOrder;
    return a.code.localeCompare(b.code);
  });

  // Extract the codes in order
  return validCoupons.map(c => c.code);
}
